import { ark } from "@ark-ui/react/factory";
import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithoutRef, ReactNode } from "react";
import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex shrink-0 items-center whitespace-nowrap font-normal [&_svg]:pointer-events-none [&_svg]:shrink-0",
  {
    variants: {
      theme: {
        default: "",
        error: "",
        warning: "",
        success: "",
        info: "",
      },
      variant: {
        solid: "",
        subtle: "",
        outline: "border bg-transparent",
        ghost: "bg-transparent",
      },
      size: {
        sm: "gap-(--badge-gap) rounded-(--badge-radius) py-(--badge-sm-py) px-(--badge-sm-px) [font-size:var(--badge-sm-font-size)] [&_svg]:size-(--badge-sm-icon-size)",
        md: "gap-(--badge-gap) rounded-(--badge-radius) py-(--badge-md-py) px-(--badge-md-px) [font-size:var(--badge-md-font-size)] [&_svg]:size-(--badge-md-icon-size)",
        lg: "gap-(--badge-gap) rounded-(--badge-radius) py-(--badge-lg-py) px-(--badge-lg-px) [font-size:var(--badge-lg-font-size)] [&_svg]:size-(--badge-lg-icon-size)",
      },
    },
    compoundVariants: [
      { theme: "default", variant: "solid", class: "bg-(--badge-default-solid-bg) text-(--badge-default-solid-fg)" },
      { theme: "default", variant: "subtle", class: "bg-(--badge-default-subtle-bg) text-(--badge-default-subtle-fg)" },
      { theme: "default", variant: "outline", class: "border-(--badge-default-outline-border) text-(--badge-default-outline-fg)" },
      { theme: "default", variant: "ghost", class: "text-(--badge-default-ghost-fg)" },
      { theme: "error", variant: "solid", class: "bg-(--badge-error-solid-bg) text-(--badge-error-solid-fg)" },
      { theme: "error", variant: "subtle", class: "bg-(--badge-error-subtle-bg) text-(--badge-error-subtle-fg)" },
      { theme: "error", variant: "outline", class: "border-(--badge-error-outline-border) text-(--badge-error-outline-fg)" },
      { theme: "error", variant: "ghost", class: "text-(--badge-error-ghost-fg)" },
      { theme: "warning", variant: "solid", class: "bg-(--badge-warning-solid-bg) text-(--badge-warning-solid-fg)" },
      { theme: "warning", variant: "subtle", class: "bg-(--badge-warning-subtle-bg) text-(--badge-warning-subtle-fg)" },
      { theme: "warning", variant: "outline", class: "border-(--badge-warning-outline-border) text-(--badge-warning-outline-fg)" },
      { theme: "warning", variant: "ghost", class: "text-(--badge-warning-ghost-fg)" },
      { theme: "success", variant: "solid", class: "bg-(--badge-success-solid-bg) text-(--badge-success-solid-fg)" },
      { theme: "success", variant: "subtle", class: "bg-(--badge-success-subtle-bg) text-(--badge-success-subtle-fg)" },
      { theme: "success", variant: "outline", class: "border-(--badge-success-outline-border) text-(--badge-success-outline-fg)" },
      { theme: "success", variant: "ghost", class: "text-(--badge-success-ghost-fg)" },
      { theme: "info", variant: "solid", class: "bg-(--badge-info-solid-bg) text-(--badge-info-solid-fg)" },
      { theme: "info", variant: "subtle", class: "bg-(--badge-info-subtle-bg) text-(--badge-info-subtle-fg)" },
      { theme: "info", variant: "outline", class: "border-(--badge-info-outline-border) text-(--badge-info-outline-fg)" },
      { theme: "info", variant: "ghost", class: "text-(--badge-info-ghost-fg)" },
    ],
    defaultVariants: {
      theme: "default",
      variant: "solid",
      size: "md",
    },
  },
);
export type BadgeProps = Omit<ComponentPropsWithoutRef<typeof ark.span>, "prefix" | "suffix"> &
  VariantProps<typeof badgeVariants> & {
    asChild?: boolean;
    prefix?: ReactNode;
    suffix?: ReactNode;
  };
export function Badge({
  className,
  theme,
  variant,
  size,
  asChild = false,
  prefix,
  suffix,
  children,
  ...props
}: BadgeProps) {
  return (
    <ark.span
      asChild={asChild}
      className={cn(badgeVariants({ theme, variant, size }), className)}
      {...props}
    >
      {prefix ? <span className="inline-flex shrink-0 items-center">{prefix}</span> : null}
      {children}
      {suffix ? <span className="inline-flex shrink-0 items-center">{suffix}</span> : null}
    </ark.span>
  );
}

/* Badge component tokens — override these to customise badges. */
:root {
  --badge-gap: 4px;
  --badge-radius: var(--radius-full);

  /* Size: sm */
  --badge-sm-py: 1px;
  --badge-sm-px: 6px;
  --badge-sm-font-size: 12px;
  --badge-sm-icon-size: 10px;

  /* Size: md */
  --badge-md-py: 3px;
  --badge-md-px: 6px;
  --badge-md-font-size: 12px;
  --badge-md-icon-size: 12px;

  /* Size: lg */
  --badge-lg-py: 4.5px;
  --badge-lg-px: 8px;
  --badge-lg-font-size: 13px;
  --badge-lg-icon-size: 12px;

  /* Theme: default */
  --badge-default-solid-bg: var(--color-primary);
  --badge-default-solid-fg: var(--color-primary-foreground);
  --badge-default-subtle-bg: var(--color-muted);
  --badge-default-subtle-fg: var(--color-muted-foreground);
  --badge-default-outline-border: color-mix(
    in oklch,
    var(--color-muted-foreground) 45%,
    var(--color-background)
  );
  --badge-default-outline-fg: var(--color-muted-foreground);
  --badge-default-ghost-fg: var(--color-muted-foreground);

  /* Theme: error */
  --badge-error-solid-bg: var(--color-error);
  --badge-error-solid-fg: var(--color-error-foreground);
  --badge-error-subtle-bg: var(--color-error-subtle);
  --badge-error-subtle-fg: var(--color-error);
  --badge-error-outline-border: color-mix(
    in oklch,
    var(--color-error) 35%,
    var(--color-background)
  );
  --badge-error-outline-fg: var(--color-error);
  --badge-error-ghost-fg: var(--color-error);

  /* Theme: warning */
  --badge-warning-solid-bg: var(--color-warning);
  --badge-warning-solid-fg: var(--color-warning-foreground);
  --badge-warning-subtle-bg: var(--color-warning-subtle);
  --badge-warning-subtle-fg: var(--color-warning);
  --badge-warning-outline-border: color-mix(
    in oklch,
    var(--color-warning) 45%,
    var(--color-background)
  );
  --badge-warning-outline-fg: var(--color-warning);
  --badge-warning-ghost-fg: var(--color-warning);

  /* Theme: success */
  --badge-success-solid-bg: var(--color-success);
  --badge-success-solid-fg: var(--color-success-foreground);
  --badge-success-subtle-bg: var(--color-success-subtle);
  --badge-success-subtle-fg: var(--color-success);
  --badge-success-outline-border: color-mix(
    in oklch,
    var(--color-success) 40%,
    var(--color-background)
  );
  --badge-success-outline-fg: var(--color-success);
  --badge-success-ghost-fg: var(--color-success);

  /* Theme: info */
  --badge-info-solid-bg: var(--color-info);
  --badge-info-solid-fg: var(--color-info-foreground);
  --badge-info-subtle-bg: var(--color-info-subtle);
  --badge-info-subtle-fg: var(--color-info);
  --badge-info-outline-border: color-mix(in oklch, var(--color-info) 40%, var(--color-background));
  --badge-info-outline-fg: var(--color-info);
  --badge-info-ghost-fg: var(--color-info);
}
